"""Health check endpoints."""
from fastapi import APIRouter, Depends
from typing import Dict, Any

router = APIRouter(prefix="/health", tags=["health"])


@router.get("")
async def health() -> Dict[str, str]:
    """Basic health check endpoint."""
    return {"status": "healthy"}


@router.get("/dependencies")
async def health_dependencies() -> Dict[str, Any]:
    """Health check for external dependencies.

    Returns status of database, storage, cache, and other dependencies.
    """
    # Minimal implementation - just return healthy status for now
    # Real implementation would check actual dependency health
    return {
        "status": "healthy",
        "dependencies": {
            "database": {"status": "healthy"},
            "storage": {"status": "healthy"},
            "cache": {"status": "healthy"},
        }
    }

